content:
[
  {
    "name": "About This Computer",
    "icon": "help-hint",
    "command": "kinfocenter"
  },
  {
    "separator": true
  },
  {
    "name": "System Preferences...",
    "icon": "settings-configure",
    "command": "systemsettings"
  },
  {
    "name": "App Store...",
    "icon": "update-none",
    "command": "plasma-discover"
  },
  {
    "separator": true
  },
  {
    "name": "Terminal",
    "icon": "konsole",
    "command": "konsole"
  },
  {
    "name": "Dolphin File Manager",
    "icon": "org.kde.dolphin",
    "command": "dolphin"
  },
  {
    "separator": true
  },
  {
    "name": "Force Quit...",
    "icon": "error",
    "command": "xkill"
  },
  {
    "separator": true
  },
  {
    "name": "Sleep",
    "icon": "system-suspend",
    "command": "systemctl suspend"
  },
  {
    "name": "Restart...",
    "icon": "system-reboot",
    "command": "qdbus6 org.kde.LogoutPrompt /LogoutPrompt promptReboot"
  },
  {
    "name": "Shut Down...",
    "icon": "system-shutdown",
    "command": "qdbus6 org.kde.LogoutPrompt /LogoutPrompt promptShutDown"
  },
  {
    "separator": true
  },
  {
    "name": "Lock Screen",
    "icon": "system-lock-screen",
    "command": "qdbus6 org.freedesktop.ScreenSaver /ScreenSaver Lock"
  },
  {
    "name": "Log Out",
    "icon": "system-log-out",
    "command": "qdbus6 org.kde.LogoutPrompt /LogoutPrompt promptLogout"
  }
]
